 72	export const derivePlayerBaseStats = (level: number): PlayerBaseStats => {
 73	  const levelOffset = Math.max(
 74	    0,
 75	    level - config.playerCharacter.stats.level.start
 76	  );
 77	  const hpGrowth = config.playerCharacter.stats.hp;
 78	  const attackGrowth = config.playerCharacter.stats.baseAttack;
 79	  const defenseGrowth = config.playerCharacter.stats.baseDefense;
 80	
 81	  return {
 82	    maxHp: Math.min(
 83	      bounds.playerCharacter.hpCap,
 84	      hpGrowth.start + levelOffset * hpGrowth.growthPerLevel
 85	    ),
 86	    attack:
 87	      attackGrowth.start +
 88	      Math.floor(levelOffset / attackGrowth.growthEveryLevels) *
 89	        attackGrowth.growthAmount,
 90	    defense:
 91	      defenseGrowth.start +
 92	      Math.floor(levelOffset / defenseGrowth.growthEveryLevels) *
 93	        defenseGrowth.growthAmount
 94	  };
 95	};
